import{_ as e,o as t,c as r,a3 as o}from"./chunks/framework.CRbjHCyB.js";const p=JSON.parse('{"title":"什么是 Catter?","description":"","frontmatter":{},"headers":[],"relativePath":"zh/catter/guide/what-is-catter.md","filePath":"zh/catter/guide/what-is-catter.md"}'),i={name:"zh/catter/guide/what-is-catter.md"};function c(l,a,n,h,d,s){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="什么是-catter" tabindex="-1">什么是 Catter? <a class="header-anchor" href="#什么是-catter" aria-label="Permalink to &quot;什么是 Catter?&quot;">​</a></h1><p>Catter 是一个构建过程拦截工具。它通过钩子拦截构建过程中的子进程创建，捕获编译和链接命令，并允许用户使用内嵌的 QuickJS 引擎编写 JavaScript 脚本来处理这些命令。</p><h2 id="动机" tabindex="-1">动机 <a class="header-anchor" href="#动机" aria-label="Permalink to &quot;动机&quot;">​</a></h2><p>Catter 是为 <a href="https://github.com/clice-io/clice" target="_blank" rel="noreferrer">clice</a> 这个新的 C++ 语言服务器而创建的。语言服务器依赖<a href="https://clang.llvm.org/docs/JSONCompilationDatabase.html" target="_blank" rel="noreferrer">编译数据库 (CDB)</a> 来了解每个源文件的编译方式，但获取 CDB 往往非常困难：</p><ul><li><strong>构建系统支持有限</strong> -- CMake 仅在使用 Makefile 或 Ninja 后端时才能生成 CDB。许多其他流行的 C++ 构建系统完全没有原生 CDB 支持。</li><li><strong>构建目录不可访问</strong> -- 当 C++ 代码作为 Python 包的一部分进行构建时，构建目录由外部管理，生成的 CDB 文件无法获取。</li><li><strong>代码生成器需要完整构建</strong> -- 像 LLVM 这样的项目使用 <code>tablegen</code> 等工具在构建时生成头文件。这些文件通过 <code>-I</code> 标志在编译命令中被引用，因此在完整构建之前，语言服务器无法正确解析 include 路径——即使你只是想阅读代码。</li></ul><p>目前没有跨平台工具能够完整解决上述所有问题，这就是我们创建 catter 的原因。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>Catter 的方式类似于 <a href="https://github.com/rizsotto/Bear" target="_blank" rel="noreferrer">Bear</a> 和 <a href="https://github.com/rizsotto/scan-build" target="_blank" rel="noreferrer">scan-build</a>。它使用平台特定的钩子（Linux 上的 <code>LD_PRELOAD</code>、macOS 上的 <code>DYLD_INSERT_LIBRARIES</code>、Windows 上的 DLL 注入）拦截子进程创建。每个被拦截的命令会发送到一个决策守护进程，该进程通过 QuickJS 运行用户提供的 JavaScript 脚本，决定如何处理每条命令。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="编译数据库生成" tabindex="-1">编译数据库生成 <a class="header-anchor" href="#编译数据库生成" aria-label="Permalink to &quot;编译数据库生成&quot;">​</a></h3><p>最主要的用例。Catter 可以跨任意构建系统捕获编译器调用，生成标准的 <code>compile_commands.json</code>，无需构建系统插件或特殊配置。</p><h3 id="链接器分析" tabindex="-1">链接器分析 <a class="header-anchor" href="#链接器分析" aria-label="Permalink to &quot;链接器分析&quot;">​</a></h3><p>通过捕获链接器命令，catter 可以重建构建目标之间的依赖图。这对 C++20 模块支持至关重要：C++ 标准规定一个程序中同名模块最多只能有一个，而&quot;程序&quot;由目标（库、可执行文件）定义。这些目标信息在 CDB 标准中是缺失的，但 catter 可以从链接器命令中推断出来。</p><h3 id="伪编译-计划中" tabindex="-1">伪编译（计划中） <a class="header-anchor" href="#伪编译-计划中" aria-label="Permalink to &quot;伪编译（计划中）&quot;">​</a></h3><p>不将编译任务转发给真正的编译器，catter 将能够生成占位目标文件。这使得构建系统可以正常运行而无需实际编译，从而在极短的时间内生成完整的 CDB。代码生成器（如 <code>tablegen</code>）仍然会正常构建——catter 会分析依赖关系以确定必须真正编译的最小工具集。</p><h3 id="构建性能分析-计划中" tabindex="-1">构建性能分析（计划中） <a class="header-anchor" href="#构建性能分析-计划中" aria-label="Permalink to &quot;构建性能分析（计划中）&quot;">​</a></h3><p>捕获构建过程中的进程时间、持续时间和父子关系，可以在浏览器中可视化渲染，帮助分析构建并行度和识别性能瓶颈。</p><h3 id="自定义脚本修补" tabindex="-1">自定义脚本修补 <a class="header-anchor" href="#自定义脚本修补" aria-label="Permalink to &quot;自定义脚本修补&quot;">​</a></h3><p>借助内嵌的 QuickJS 引擎，用户可以编写 JavaScript 脚本来动态修改、重定向或注入构建命令的逻辑——无需修改原始构建文件。</p><h2 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h2><p>Catter 由三个部分组成：</p><ul><li><strong>HOOK</strong> -- 注入到进程中的平台特定库，用于拦截子进程创建。</li><li><strong>PROXY</strong>（<code>catter-proxy</code>）-- 管理钩子注入并充当编译器包装器，将被拦截的命令转发给决策守护进程。</li><li><strong>DECISION</strong>（<code>catter</code>）-- 主守护进程。运行 JS 运行时，接收来自 proxy 的被拦截命令，并决定如何处理每条命令。</li></ul><p>关于架构和 IPC 流程的详细介绍，请参阅<a href="./../design/architecture">设计文档</a>。</p>',23)])])}const b=e(i,[["render",c]]);export{p as __pageData,b as default};
